INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,5,'I''ve repaired my bike in many places, but this shop is probably the most satisfactory. I passed by this place on a business trip and saw it was crowded, so I researched and stopped by to experience it. After experiencing it, I realized that there are no 10 points but ))). My AB 110 bike had its clutch cleaned, minor repairs, and a low throttle problem fixed by the mechanic, all done very well. The price is reasonable, no fake problems or anything. The owner and the mechanic are very good.','Do Ky Lam','GOOGLE',false,'2025-04-28 18:07:10.939585+00'::timestamptz FROM repair_shop WHERE external_id='ChIJ11fb670udTERxZnZqMthkZ4';
INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,5,'The repair shop is very good and efficient, with reasonable prices compared to the general price level in Saigon. After the repair, I forgot that my motorbike had a weak starter, so I asked the owner to check it for me. He even recharged the battery for me without charging extra. Anyone in District 11 with motorbike problems should definitely come here!','Khánh Huyền Phan','GOOGLE',false,'2025-06-30 12:47:54.883896+00'::timestamptz FROM repair_shop WHERE external_id='ChIJ11fb670udTERxZnZqMthkZ4';
INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,1,'I went to the shop on April 26th because my motorbike wouldn''t start. The mechanic told me the battery and starter motor were faulty (even though I had just replaced the battery not long ago, specifically in January 2025). He suggested replacing it, but when I asked about the charger, he said it was a matter of luck. After replacing the battery, my motorbike still wouldn''t start. I thought it was initially a problem with the motorbike. Today, after I got home, the owner said there was nothing wrong with the motorbike and cleaned it for me. He said if the motorbike wasn''t broken, they''d replace the battery. As a student, I don''t know much about motorbikes, so this was unavoidable. Please consider this carefully before going to this place to avoid wasting money. My motorbike wasn''t repaired properly, and I ended up wasting money.','Vy Yến','GOOGLE',false,'2025-05-03 06:51:38.226402+00'::timestamptz FROM repair_shop WHERE external_id='ChIJ11fb670udTERxZnZqMthkZ4';
