INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,5,'Today felt like I was going crazy, huhu. I was planning to ride my motorbike to Vung Tau. Just after crossing the ferry and driving a little into the mangrove forest, I heard a loud bang and slammed on the brakes. Then the bike started making clicking noises. My sister and I just stood there laughing, not knowing what to do, huhu. A guy stopped to help, but he said he couldn''t do it and told me to call for roadside assistance. I searched online and found one place, but they were in Ho Chi Minh City and said they could only tow the bike back, not repair it. He told me to try contacting nearby repair shops. So I randomly searched on the map and called, huhu. Most refused, but luckily a local owner answered. He briefly asked about the situation and location. He was helping another vehicle that was passing by. He checked and fixed it temporarily because my bike was badly damaged and needed to be taken to a shop with the right parts. So I went back to the shop with him. The repairman was very conscientious, checked everything thoroughly, and the price was great. He even offered us drinks! 😿 After talking to him, we found out he''s part of the mobile tire repair team in Can Gio district. After fixing our tire, we had a new flat tire case and called him right away. Super dedicated and enthusiastic. If you ever encounter problems in the mangrove forest, call Mr. Thai! We were so lucky to get through to him; otherwise, we would have probably just been crying.','Hiemal Kim','GOOGLE',false,'2026-01-10 15:26:54.050752+00'::timestamptz FROM repair_shop WHERE external_id='ChIJ6cXlv345dTERoKo8sIOh2zQ';
INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,5,'The product is of good quality and comes with a 6-month warranty.','Thu Vân Lê Thị','GOOGLE',false,'2025-08-28 10:27:39.166928+00'::timestamptz FROM repair_shop WHERE external_id='ChIJ6cXlv345dTERoKo8sIOh2zQ';
