INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,1,'I don''t like this shop. They always park a traffic police car in front of the shop to show off or something. The owner is annoying. He only repairs nice bikes, but he gets annoyed with my old, beat-up bike. I was waiting for him to replace the lock, and he kept saying "wait a minute" even though the shop had no customers. So I waited for about 30 minutes while he sat there munching on a sausage. Because my bike was old, when he tried to put the lock back on, he couldn''t and started yelling, "What kind of bike is this? It breaks everything you touch!" While he was fixing my bike, another guy came in (on an Air Black) and he left mine to fix that guy''s bike. Seriously, there''s a limit to how arrogant people can be. I''m never going back to this shop again.','Ngoc Lam','GOOGLE',false,'2018-08-26 05:37:25.678017+00'::timestamptz FROM repair_shop WHERE external_id='ChIJBYVW1YM6dTERnQtTVwMPxkw';
