INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,1,'I don''t have time to go fix the car, at first I stopped by to ask how much the Vision battery cost, they said 365k then when I went to fix it they said the battery cost something like 395k ok I accepted to replace it, replacing the remote battery at Honda is only 30k here is 50k, I know this is not an authorized shop because it was raining near my house that day so it was ok. Less than a month after the repair, I was driving in the middle of the road and turned off the engine, which was extremely dangerous, 7 or 8 times, I stopped by to ask, they said this and that, intentionally not taking responsibility while the car had already had its throttle cleaned, he said he saw a girl and wanted to say whatever he wanted, I used to be a Honda employee so I know these things very well. The car I bought before has never had this problem and I drive the car very carefully. These shops only know how to show off to customers, working at a Honda authorized shop, if you complain, they will resolve it for you immediately. I don''t know where 75 customers rated 5 stars, they probably all bought it for nothing, so infuriating... customers who want to repair should go to the authorized Head store, what can they complain about...','Trúc Lâm Đinh','GOOGLE',false,'2025-11-25 09:25:55.525202+00'::timestamptz FROM repair_shop WHERE external_id='ChIJoyrglw8rdTERGe4wwUhu7JU';
INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,1,'My front tire got punctured by a nail. Initially, they quoted 40k VND for patching, which I agreed to. After removing the nail, they said it was on the side of the tire and the patch wouldn''t stick (it would be glued in place), and suggested replacing the tire. How can you expect to last if you just make up excuses like that?','diego tristant','GOOGLE',false,'2025-10-08 02:05:21.140008+00'::timestamptz FROM repair_shop WHERE external_id='ChIJoyrglw8rdTERGe4wwUhu7JU';
INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,5,'The shop is very enthusiastic, provides excellent advice, and the prices are reasonable; they don''t overcharge customers. The staff are friendly. If I ever have any problems with my car in the future, I''ll definitely go to this shop first.','binh lethimy','GOOGLE',false,'2025-08-13 10:35:05.79848+00'::timestamptz FROM repair_shop WHERE external_id='ChIJoyrglw8rdTERGe4wwUhu7JU';
