INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,5,'The repairman is conscientious, doesn''t raise prices, and doesn''t charge customers for unnecessary services. I came to get my tire fixed, and because I had a big screw stuck in it, there were many holes (4-5). He checked and fixed every hole, so after fixing 2 holes, he discovered a 3rd hole and asked me if he wanted to replace the tube. Seeing me hesitate, he said he would just let me fix it and charge me for the 2 holes. After that, he discovered another hole so he told me to replace the tube, and he wouldn''t charge me for the repair. He gave me 2 types of tubes, 110k and 120k, to choose from, and only asked for an extra 10k for labor. I chose the 120k type and then gave him some extra money.','Phạm Ngọc Thiện','GOOGLE',false,'2025-10-17 05:22:34.663348+00'::timestamptz FROM repair_shop WHERE external_id='ChIJuQs5s7QvdTERUcR4qCQb7nY';
