INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,5,'Ba Long auto repair shop is reputable, the owner is very easy-going and funny, the shop diagnoses problems quickly, repairs quickly, and the price is cheap. I''ve had my car repaired at this shop for a few years now. Ever since I had a broken-down car, I''ve been a regular customer at this shop. Now I''m so familiar with it that many times when I come in to pump my tires or increase the chain, he does it for free. The car wash is clean and the price is the cheapest in the area. He washes thoroughly and cleans thoroughly. As for patching tires, he does both pressing and patching. Changing a tube is only 80k.','con nhikhuc (Nicole)','GOOGLE',false,'2025-11-23 11:53:36.615063+00'::timestamptz FROM repair_shop WHERE external_id='ChIJuUBWEcIndTERFkneW0LQUPg';
