INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,1,'This is a repair shop everyone should avoid. Their work is terrible. They replaced a sprocket and chain set for a customer but were missing parts. The prices are exorbitant. Everyone should be extremely careful and stay away from this shop.','Huy Trần','GOOGLE',false,'2025-02-22 10:11:26.573345+00'::timestamptz FROM repair_shop WHERE external_id='ChIJycx5zJEndTERr-R8OeuYf4c';
INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,1,'You should avoid this shop. People come to the tire repair shop and they don''t bother to fix it. They say they''re busy, while they''re sitting around doing nothing (it probably doesn''t cost much to fix it). They ask for a new tube and they charge exorbitant prices. After they''re done, they screw the tire in, the brake gets stuck, and they can''t go. After they adjust it, the chain is too tight and they make you squeal. Goodbye to this shop. Everyone, be careful not to come in, or you''ll lose both money and health.','Vy Minh Tâm','GOOGLE',false,'2025-05-15 02:31:36.749664+00'::timestamptz FROM repair_shop WHERE external_id='ChIJycx5zJEndTERr-R8OeuYf4c';
INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,1,'Guys, avoid this place! My car''s remote control was sometimes working and sometimes not. They didn''t quote the price for repairs beforehand, then said the battery was dead, which I didn''t replace. Then they opened the air filter and said it was dirty, so I replaced it. Afterward, they charged 680k, the air filter 130k, and then said the wiring harness was broken for 550k, without even mentioning the wiring or pointing out the problem. They just said the battery was dead and I didn''t replace it. I asked if there was a warranty, and the owner said they''d replace the battery and the wiring harness was under warranty because they were worried it might break again after a few days, but they still charged me 550k. It''s scary!','Ý Lương','GOOGLE',false,'2025-01-06 10:55:33.281123+00'::timestamptz FROM repair_shop WHERE external_id='ChIJycx5zJEndTERr-R8OeuYf4c';
INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,1,'This shop was doing reasonably well at first, but later on, they became increasingly ostentatious in order to extort money from customers. They would replace parts instead of repairing them, and on average, they would overcharge by at least 100k VND for each replacement. For example, a 25k VND item would be increased to 125k VND, or a 270k VND item to 420k VND. I understand they charge for labor, but with this kind of business practice, they probably won''t last long.','Quang Nguyen','GOOGLE',false,'2025-07-27 13:13:45.950754+00'::timestamptz FROM repair_shop WHERE external_id='ChIJycx5zJEndTERr-R8OeuYf4c';
