INSERT INTO repair_review (shop_id,rating,comment,author_name,source,is_anonymous,reviewed_at) SELECT shop_id,5,'I''m extremely satisfied with the car repair service here. My car had a pretty serious problem, and I''d taken it to several other places without success, but when I got it, the mechanics correctly identified the issue and fixed it completely. A big plus is that the staff are very honest, they check thoroughly and give clear price quotes before starting any work, absolutely no "making up problems" or trying to force people to replace parts unnecessarily. The prices are reasonable, and the replacement parts have proper warranties. The owner and mechanics are all enthusiastic and friendly. I will definitely be a long-term customer and recommend this place to my friends.','Nhân Nguyễn','GOOGLE',false,'2026-05-18 14:55:15.191439+00'::timestamptz FROM repair_shop WHERE external_id='ChIJz1807HQpdTERzflHWfAc5UM';
